// ====================================
// PROCESAR RESPUESTAS DE FORMULARIO WHATSAPP
// ====================================
const entries = $input.all();
const formResponses = [];

for (const entry of entries) {
  const body = entry.json.body;

  // Verificar que sea un mensaje del formulario
  if (body?.entry?.[0]?.changes?.[0]?.value?.messages) {
    const messages = body.entry[0].changes[0].value.messages;

    for (const message of messages) {
      // Filtrar solo respuestas de formulario (nfm_reply)
      if (message.type === 'interactive' && 
          message.interactive?.type === 'nfm_reply') {

        const phone = message.from;
        const messageId = message.id;
        const timestamp = message.timestamp;

        // Extraer datos del formulario
        const responseJson = message.interactive.nfm_reply.response_json;
        const formData = JSON.parse(responseJson);

        // LOG COMPLETO PARA DEBUG
        console.log('=== FORM DATA COMPLETO ===');
        console.log(JSON.stringify(formData, null, 2));

        // Extraer valores con múltiples variantes posibles
        const nombre = (
          formData.screen_0_Nombre_0 || 
          formData.Nombre_0395a7 || 
          formData.Nombre || 
          formData.nombre || 
          ''
        ).trim();

        const apellido = (
          formData.screen_0_Apellido_1 || 
          formData.Apellido_a46de2 || 
          formData.Apellido || 
          formData.apellido || 
          ''
        ).trim();

        const telefono = (
          formData.screen_0_Telefono_2 || 
          formData.Telefono_fe1365 || 
          formData.Telefono || 
          formData.telefono || 
          ''
        ).trim();

        const ciudad = (
          formData.screen_0_Ciudad_3 || 
          formData.Ciudad_c7e891 || 
          formData.Ciudad || 
          formData.ciudad || 
          ''
        ).trim();

        const direccion = (
          formData.screen_0_Direccion_4 || 
          formData.screen_0_Direccion_3 || 
          formData.Direccion_d9fd55 || 
          formData.Direccion || 
          formData.direccion || 
          ''
        ).trim();

        const tipoNegocio = (
          formData.screen_0_Tipo_de_negocio_5 || 
          formData.screen_0_Tipo_de_negocio_4 || 
          formData.Tipo_de_negocio_9f606b || 
          formData['Tipo de negocio'] || 
          formData.tipo_negocio || 
          formData.Tipo_de_negocio ||
          ''
        ).trim();

        // LOG DE CAMPOS EXTRAÍDOS
        console.log('=== CAMPOS EXTRAÍDOS ===');
        console.log('Nombre:', nombre);
        console.log('Apellido:', apellido);
        console.log('Teléfono:', telefono);
        console.log('Ciudad:', ciudad);
        console.log('Dirección:', direccion);
        console.log('Tipo Negocio:', tipoNegocio);

        // Normalizar teléfono (solo números)
        const phoneFormatted = phone.replace(/[^0-9]/g, '');

        // Fecha formateada
        const date = new Date(parseInt(timestamp) * 1000);
        const fechaFormateada = date.toLocaleString('es-CO', {
          timeZone: 'America/Bogota',
          year: 'numeric',
          month: '2-digit',
          day: '2-digit',
          hour: '2-digit',
          minute: '2-digit',
          second: '2-digit'
        });

        const nombreCompleto = `${nombre} ${apellido}`.trim();

// ====================================
// MENSAJE DE WHATSAPP - VERSIÓN MEJORADA
// ====================================

// Construir el mensaje de texto para WhatsApp
const mensajeWhatsApp = "Hola, soy " + nombre + " " + apellido + " y necesito un crédito, quiero más información";

// Construir el mensaje completo que se mostrará
const whatsappMessage = 
  "✅ ¡Listo " + nombreCompleto + "!\n\n" +
  "Tus datos fueron recibidos con éxito. ✨\n\n" +
  "💡 Habla AHORA MISMO con un asesor y recibe tu crédito lo antes posible. 🚀\n\n" +
  "📲 TOCA AQUÍ para hablar con un asesor:\n" +
  "https://wa.me/595974270790?text=" + encodeURIComponent(mensajeWhatsApp) + "\n\n" +
  "💰 Créditos El Paisa\n" +
  "Tu mejor opción en créditos rápida y confiable.";
        // ====================================
        // PAYLOAD PARA WHATSAPP API
        // ====================================
        const whatsappApiPayload = {
          messaging_product: "whatsapp",
          to: phoneFormatted,
          type: "text",
          text: {
            body: whatsappMessage
          }
        };

        // ====================================
        // HTML PARA CORREO
        // ====================================
        const emailHTML = `<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <style>
    body { font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif; background: #f4f4f4; margin: 0; padding: 0; }
    .container { max-width: 650px; margin: 30px auto; background: white; border-radius: 12px; overflow: hidden; box-shadow: 0 4px 20px rgba(0,0,0,0.1); }
    .header { background: linear-gradient(135deg, #25D366 0%, #128C7E 100%); color: white; padding: 40px 30px; text-align: center; }
    .header h1 { margin: 0; font-size: 28px; font-weight: 600; }
    .header p { margin: 10px 0 0 0; opacity: 0.95; font-size: 16px; }
    .content { padding: 40px 30px; }
    .field { margin: 20px 0; padding: 18px; background: #f8f9fa; border-left: 4px solid #25D366; border-radius: 8px; }
    .label { font-weight: 600; color: #128C7E; font-size: 13px; text-transform: uppercase; letter-spacing: 0.5px; margin-bottom: 8px; display: block; }
    .value { color: #2c3e50; font-size: 17px; margin: 0; word-break: break-word; }
    .footer { background: #f8f9fa; padding: 25px; text-align: center; color: #6c757d; font-size: 13px; border-top: 1px solid #e9ecef; }
    .badge { display: inline-block; background: #25D366; color: white; padding: 5px 12px; border-radius: 20px; font-size: 12px; font-weight: 600; margin-top: 10px; }
  </style>
</head>
<body>
  <div class="container">
    <div class="header">
      <h1>💰 Nuevo Registro</h1>
      <p>Solicitud de préstamo recibida</p>
      <span class="badge">CREDITOS EL PAISA</span>
    </div>
    <div class="content">
      <div class="field">
        <span class="label">👤 Nombre Completo</span>
        <p class="value">${nombreCompleto}</p>
      </div>
      <div class="field">
        <span class="label">📱 Teléfono WhatsApp</span>
        <p class="value">+${phoneFormatted}</p>
      </div>
      <div class="field">
        <span class="label">📱 Teléfono del Formulario</span>
        <p class="value">${telefono}</p>
      </div>
      <div class="field">
        <span class="label">🌆 Ciudad</span>
        <p class="value">${ciudad}</p>
      </div>
      <div class="field">
        <span class="label">📍 Dirección</span>
        <p class="value">${direccion}</p>
      </div>
      <div class="field">
        <span class="label">🏢 Tipo de Negocio</span>
        <p class="value">${tipoNegocio}</p>
      </div>
      <div class="field">
        <span class="label">📅 Fecha y Hora</span>
        <p class="value">${fechaFormateada}</p>
      </div>
    </div>
    <div class="footer">
      <p><strong>Sistema de Registro Automático</strong></p>
      <p>Este mensaje fue generado automáticamente por WhatsApp Business</p>
      <p style="margin-top: 15px; color: #128C7E; font-weight: 600;">Creditos El Paisa © 2025</p>
    </div>
  </div>
</body>
</html>`;

        // ====================================
        // DATOS PARA GOOGLE SHEETS
        // ====================================
        const sheetData = {
          nombre: nombre,
          apellido: apellido,
          nombre_completo: nombreCompleto,
          telefono_whatsapp: `+${phoneFormatted}`,
          telefono_formulario: telefono,
          ciudad: ciudad,
          direccion: direccion,
          tipo_negocio: tipoNegocio,
          fecha: fechaFormateada,
          fecha_iso: date.toISOString(),
          message_id: messageId,
          timestamp: timestamp
        };

        // Log para debugging
        console.log('✅ Formulario procesado:', nombreCompleto);

        // ====================================
        // OBJETO COMPLETO CON TODAS LAS VARIABLES
        // ====================================
        formResponses.push({
          // Datos básicos
          phone: phone,
          phone_formatted: phoneFormatted,
          message_id: messageId,
          timestamp: timestamp,

          // Fechas
          fecha: date.toISOString(),
          fecha_formateada: fechaFormateada,

          // Datos del cliente
          nombre: nombre,
          apellido: apellido,
          nombre_completo: nombreCompleto,
          telefono_form: telefono,
          ciudad: ciudad,
          direccion: direccion,
          tipo_negocio: tipoNegocio,

          // Contenido para WhatsApp (texto plano)
          whatsapp_message: whatsappMessage,

          // Payload completo para WhatsApp API (objeto JSON)
          whatsapp_api_payload: whatsappApiPayload,

          // Contenido para Email
          email_html: emailHTML,
          email_subject: `🔔 Nuevo registro WhatsApp - ${nombreCompleto}`,

          // Datos para Google Sheets
          sheet_data: sheetData,

          // Data completa del formulario (respaldo)
          form_data_complete: formData
        });
      }
    }
  }
}

// Log final
console.log('=============================');
console.log('Total formularios procesados:', formResponses.length);
console.log('=============================');

// Si no hay respuestas de formulario, retornar array vacío
if (formResponses.length === 0) {
  console.log('⚠️ No se encontraron respuestas de formulario');
  return [];
}

// Retornar los datos procesados
return formResponses;
